def parse_nested_json(
    data: Union[Dict[str, Any], List[Any], str],
    path: str,
    default: Any = None
) -> Optional[Any]:
    """
    Safely parse deeply nested JSON data using dot and bracket notation.

    Args:
        data: JSON data as dict, list, or JSON string
        path: Path to the desired value using dot and bracket notation.
              Examples: "user.profile.settings.theme", "users[0].name", 
                       "data[2].items[0].value"
        default: Value to return if the path doesn't exist (default: None)

    Returns:
        The value at the specified path, or default if not found.
        Returns None for missing keys/values (unless default is specified).

    Raises:
        ValueError: If the JSON string is invalid or path syntax is malformed.
        TypeError: If data is not a valid JSON structure.

    Examples:
        >>> data = {"user": {"profile": {"settings": {"theme": "dark"}}}}
        >>> parse_nested_json(data, "user.profile.settings.theme")
        'dark'

        >>> parse_nested_json(data, "user.missing.key")
        None

        >>> data = {"users": [{"name": "Alice"}, {"name": "Bob"}]}
        >>> parse_nested_json(data, "users[1].name")
        'Bob'
    """

    # Convert JSON string to Python object if needed
    if isinstance(data, str):
        try:
            data = json.loads(data)
        except json.JSONDecodeError as e:
            raise ValueError(f"Invalid JSON string: {e}") from e

    if not isinstance(data, (dict, list)):
        raise TypeError(f"Expected dict or list, got {type(data).__name__}")

    if not path or not isinstance(path, str):
        return default

    # Circular reference detection setup
    seen_ids = set()

    def _safe_get(obj: Any, key: str) -> Any:
        """Safely get a value from dict or list with proper error handling."""
        obj_id = id(obj)
        if obj_id in seen_ids:
            raise ValueError(f"Circular reference detected at key: {key}")
        seen_ids.add(obj_id)

        try:
            if isinstance(obj, dict):
                return obj.get(key)
            elif isinstance(obj, list):
                try:
                    idx = int(key)
                    if 0 <= idx < len(obj):
                        return obj[idx]
                    return None
                except ValueError:
                    return None
            else:
                return None
        finally:
            seen_ids.discard(obj_id)

    def _parse_path(current: Any, remaining_path: str) -> Any:
        """Recursively parse the path with proper type handling."""
        if not remaining_path:
            return current

        # Split on first occurrence of . or [
        match = re.match(r'^([^\.\[]+)(.*)$', remaining_path)
        if not match:
            return default

        key, rest = match.groups()

        # Get the value for current key
        value = _safe_get(current, key)

        if value is None:
            return default

        # Process the rest of the path
        if not rest:
            return value

        # Handle array index syntax like [0]
        if rest.startswith('['):
            end_bracket = rest.find(']')
            if end_bracket == -1:
                raise ValueError(f"Mismatched brackets in path: {path}")

            index_str = rest[1:end_bracket]
            try:
                index = int(index_str)
            except ValueError:
                raise ValueError(f"Invalid array index in path '{path}': {index_str}")

            if not isinstance(value, list):
                return default

            if not (0 <= index < len(value)):
                return default

            next_value = value[index]
            next_path = rest[end_bracket + 1:]

            # Remove leading dot if present
            if next_path.startswith('.'):
                next_path = next_path[1:]

            return _parse_path(next_value, next_path)

        # Handle dot notation
        elif rest.startswith('.'):
            return _parse_path(value, rest[1:])

        else:
            # Continue with the rest of the path
            return _parse_path(value, rest)

    try:
        result = _parse_path(data, path)
        return result if result is not None else default
    except Exception as e:
        error_msg = f"Error parsing path '{path}': {str(e)}"
        raise RuntimeError(error_msg) from e


