from typing import Any, Optional, Union, Dict, List, Tuple, TypeVar
import json

T = TypeVar('T')

class NestedJSONParserError(Exception):
    """Base class for parsing errors."""
    pass

class CircularReferenceError(NestedJSONParserError):
    """Raised when a circular reference is detected."""
    pass

class InvalidPathError(NestedJSONParserError):
    """Raised when the path syntax is invalid."""
    pass

class ArrayIndexError(NestedJSONParserError):
    """Raised when an array index is out of bounds or invalid."""
    pass

def parse_nested_json(
    data: Union[Dict[str, Any], List[Any], str],
    path: str,
    default: Optional[T] = None,
    *,
    _visited: Optional[List[int]] = None
) -> Tuple[Optional[T], Optional[str]]:
    """
    Parses deeply nested JSON data using a path syntax.

    Args:
        data: The JSON data to parse (can be dict, list, or JSON string)
        path: The path to the value in dot notation (e.g., "user.profile.settings.theme")
        default: Default value to return if path not found or error occurs
        _visited: Internal use only - tracks visited objects for circular reference detection

    Returns:
        A tuple containing:
        - The parsed value (or default if not found/error)
        - An error message if something went wrong (None if successful)

    Examples:
        >>> data = {'user': {'profile': {'settings': {'theme': 'dark'}}}}
        >>> parse_nested_json(data, 'user.profile.settings.theme')
        ('dark', None)

        >>> data = {'users': [{'name': 'Alice'}, {'name': 'Bob'}]}
        >>> parse_nested_json(data, 'users[1].name')
        ('Bob', None)

        >>> parse_nested_json(data, 'nonexistent.path', 'default')
        ('default', "Key 'nonexistent' not found")
    """
    # Initialize visited list for circular reference detection
    if _visited is None:
        _visited = []

    # Convert string to JSON if needed
    if isinstance(data, str):
        try:
            data = json.loads(data)
        except json.JSONDecodeError:
            return default, "Invalid JSON string"

    # Handle empty path
    if not path:
        return data, None

    # Split path into components
    try:
        path_components = _parse_path(path)
    except InvalidPathError as e:
        return default, str(e)

    current_value = data
    current_path = []

    try:
        for component in path_components:
            current_path.append(component)

            if isinstance(component, str) and isinstance(current_value, dict):
                if component not in current_value:
                    return default, f"Key '{component}' not found at path '{'.'.join(map(str, current_path[:-1]))}'"
                current_value = current_value[component]
            elif isinstance(component, int) and isinstance(current_value, list):
                if component < 0 or component >= len(current_value):
                    raise ArrayIndexError(f"Index {component} out of bounds for array at path '{'.'.join(map(str, current_path[:-1]))}'")
                current_value = current_value[component]
            else:
                expected = "dict" if isinstance(component, str) else "list"
                actual = type(current_value).__name__
                return default, f"Expected {expected} at path '{'.'.join(map(str, current_path[:-1]))}', found {actual}"

            # Circular reference detection
            if isinstance(current_value, (dict, list)):
                obj_id = id(current_value)
                if obj_id in _visited:
                    raise CircularReferenceError(f"Circular reference detected at path '{'.'.join(map(str, current_path))}'")
                _visited.append(obj_id)

        return current_value, None

    except NestedJSONParserError as e:
        return default, str(e)
    except Exception as e:
        return default, f"Unexpected error: {str(e)}"

def _parse_path(path: str) -> List[Union[str, int]]:
    """
    Parses a path string into components.

    Args:
        path: The path string (e.g., "user.profile.settings[0].theme")

    Returns:
        List of path components (strings and integers for array indices)

    Raises:
        InvalidPathError: If the path syntax is invalid
    """
    if not path:
        return []

    components = []
    current = ''
    in_array = False
    array_index = ''

    for char in path:
        if char == '[':
            if in_array:
                raise InvalidPathError("Nested array brackets are not allowed")
            if current:
                components.append(current)
                current = ''
            in_array = True
        elif char == ']':
            if not in_array:
                raise InvalidPathError("Unmatched closing bracket")
            if not array_index:
                raise InvalidPathError("Empty array index")
            try:
                components.append(int(array_index))
            except ValueError:
                raise InvalidPathError(f"Invalid array index: '{array_index}'")
            in_array = False
            array_index = ''
        elif in_array:
            if char.isdigit():
                array_index += char
            else:
                raise InvalidPathError(f"Invalid character '{char}' in array index")
        elif char == '.':
            if current:
                components.append(current)
                current = ''
        else:
            current += char

    if in_array:
        raise InvalidPathError("Unclosed array bracket")

    if current:
        components.append(current)

    return components
